import { LiveClient } from "@/components/LiveClient";
import { getYouTubeVideos } from "@/lib/youtube";

export default async function LivePage() {
  const videos = await getYouTubeVideos();

  const live = videos.find((v) => v.liveBroadcastContent === "live");

  return (
    <main style={{ background: "#000", color: "#fff", minHeight: "100vh", padding: "20px" }}>
      
      {/* HAUT */}
      <div style={{ display: "flex", gap: "20px" }}>

        {/* PLAYER */}
        <div style={{ flex: 1 }}>
          <div
            style={{
              width: "100%",
              height: "400px",
              background: "black",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: "28px",
              fontWeight: "bold",
            }}
          >
            {live ? (
              <iframe
                width="100%"
                height="100%"
                src={`https://www.youtube.com/embed/${live.id}`}
                style={{ border: "none" }}
                allowFullScreen
              />
            ) : (
              "🔴 LIVE OFFLINE"
            )}
          </div>
        </div>

        {/* CHAT */}
        <div
          style={{
            width: "300px",
            height: "400px",
            background: "#111",
            padding: "10px",
            overflow: "hidden",
          }}
        >
          <LiveClient />
        </div>

      </div>

      {/* BAS : VIDEOS */}
      <div
        style={{
          marginTop: "20px",
          display: "grid",
          gridTemplateColumns: "repeat(3, 1fr)",
          gap: "10px",
        }}
      >
        {videos.slice(0, 6).map((v) => (
          <a
            key={v.id}
            href={`https://www.youtube.com/watch?v=${v.id}`}
            target="_blank"
            style={{ textDecoration: "none", color: "white" }}
          >
            <div style={{ background: "#111", padding: "5px" }}>
              <img
                src={v.thumbnail}
                style={{ width: "100%", display: "block" }}
              />
              <div style={{ fontSize: "14px", marginTop: "5px" }}>
                {v.title}
              </div>
            </div>
          </a>
        ))}
      </div>

    </main>
  );
}